 1	import type { FC } from 'react';
 2	import { useLocation, useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import { Tab, Tabs, TabTitleText } from '@patternfly/react-core';
 5	
 6	type RoutedTab = {
 7	  name: string;
 8	  to: string;
 9	  onClick?: () => void;
10	};
11	
12	type RoutedTabsProps = {
13	  tabs: RoutedTab[];
14	};
15	
16	const RoutedTabs: FC<RoutedTabsProps> = ({ tabs }) => {
17	  const location = useLocation();
18	  const navigate = useNavigate();
19	  const activeTab = tabs.find((tab) => location.pathname === tab.to) ?? tabs[0];
20	
21	  return (
22	    <Tabs
23	      activeKey={activeTab.to}
24	      onSelect={(_, eventKey) => {
25	        const selectedTab = tabs.find((tab) => tab.to === eventKey);
26	
27	        if (selectedTab) {
28	          navigate(selectedTab.to);
29	          selectedTab.onClick?.();
30	        }
31	      }}
32	    >
33	      {tabs.map((tab) => (
34	        <Tab key={tab.to} eventKey={tab.to} title={<TabTitleText>{tab.name}</TabTitleText>} />
35	      ))}
36	    </Tabs>
37	  );
38	};
39	
40	export default RoutedTabs;

