 1	import { MemoryRouter } from 'react-router-dom-v5-compat';
 2	
 3	import { beforeEach, describe, expect, it } from '@jest/globals';
 4	import { render, screen } from '@testing-library/react';
 5	import userEvent from '@testing-library/user-event';
 6	
 7	import RoutedTabs from '../RoutedTabs';
 8	
 9	const mockNavigate = jest.fn();
10	
11	jest.mock('react-router-dom-v5-compat', () => ({
12	  ...jest.requireActual('react-router-dom-v5-compat'),
13	  useNavigate: () => mockNavigate,
14	}));
15	
16	const renderWithRouter = (tabs: any[], initialPath = '/overview') =>
17	  render(
18	    <MemoryRouter initialEntries={[initialPath]}>
19	      <RoutedTabs tabs={tabs} />
20	    </MemoryRouter>,
21	  );
22	
23	describe('RoutedTabs', () => {
24	  const mockOnClick = jest.fn();
25	
26	  beforeEach(() => {
27	    jest.clearAllMocks();
28	  });
29	
30	  it('renders tabs with correct names', () => {
31	    const tabs = [
32	      { name: 'Overview', to: '/overview' },
33	      { name: 'Settings', to: '/settings' },
34	    ];
35	    renderWithRouter(tabs);
36	
37	    expect(screen.getByRole('tab', { name: 'Overview' })).toBeInTheDocument();
38	    expect(screen.getByRole('tab', { name: 'Settings' })).toBeInTheDocument();
39	  });
40	
41	  it('shows active tab based on current path', () => {
42	    const tabs = [
43	      { name: 'Overview', to: '/overview' },
44	      { name: 'Settings', to: '/settings' },
45	    ];
46	    renderWithRouter(tabs, '/settings');
47	
48	    expect(screen.getByRole('tab', { name: 'Settings' })).toHaveAttribute('aria-selected', 'true');
49	    expect(screen.getByRole('tab', { name: 'Overview' })).toHaveAttribute('aria-selected', 'false');
50	  });
51	
52	  it('defaults to first tab when path does not match', () => {
53	    const tabs = [
54	      { name: 'Overview', to: '/overview' },
55	      { name: 'Settings', to: '/settings' },
56	    ];
57	    renderWithRouter(tabs, '/unknown');
58	
59	    expect(screen.getByRole('tab', { name: 'Overview' })).toHaveAttribute('aria-selected', 'true');
60	  });
61	
62	  it('navigates when tab is clicked', async () => {
63	    const user = userEvent.setup();
64	    const tabs = [
65	      { name: 'Overview', to: '/overview' },
66	      { name: 'Settings', to: '/settings' },
67	    ];
68	    renderWithRouter(tabs, '/overview');
69	
70	    await user.click(screen.getByRole('tab', { name: 'Settings' }));
71	
72	    expect(mockNavigate).toHaveBeenCalledWith('/settings');
73	  });
74	
75	  it('calls onClick handler when provided', async () => {
76	    const user = userEvent.setup();
77	    const tabs = [
78	      { name: 'Overview', to: '/overview' },
79	      { name: 'Settings', to: '/settings', onClick: mockOnClick },
80	    ];
81	    renderWithRouter(tabs, '/overview');
82	
83	    await user.click(screen.getByRole('tab', { name: 'Settings' }));
84	
85	    expect(mockOnClick).toHaveBeenCalledTimes(1);
86	    expect(mockNavigate).toHaveBeenCalledWith('/settings');
87	  });
88	
89	  it('handles empty tabs array', () => {
90	    expect(() => renderWithRouter([])).toThrow();
91	  });
92	});

